+// Custom error class with typed error codes
+export class VersionNegotiationError extends Error {
+  constructor(
+    message: string,
+    public code: 'VERSION_MISMATCH' | 'UNSUPPORTED_CAPABILITY' | 'INVALID_HANDSHAKE'
